// Extraer el registro recién insertado desde el payload de Supabase
// Supabase DB Webhooks envían la fila en body.record
const record = $input.first().json.body?.record || $input.first().json.record || $input.first().json;

if (!record || !record.whatsapp) {
  throw new Error('No se encontró el registro de beta_businesses en el payload.');
}

// Limpiar y normalizar el número de WhatsApp
let phone = record.whatsapp.replace(/[^\d+]/g, '');
if (!phone.startsWith('+')) {
  // Asumir Colombia si no tiene código de país
  phone = '+57' + phone.replace(/^57/, '');
}

return {
  json: {
    id: record.id,
    owner_name: record.owner_name,
    business_name: record.business_name,
    business_type: record.business_type,
    neighborhood: record.neighborhood,
    city: record.city || 'Medellín',
    whatsapp: phone,
    email: record.email,
    instagram: record.instagram || '',
    wants_free_pilot: record.wants_free_pilot,
    created_at: record.created_at
  }
};

// Construir el mensaje de bienvenida por WhatsApp
const data = $input.first().json;

const primerNombre = data.owner_name.split(' ')[0];

const mensaje = `🏟️ *¡Bienvenido a FanFest AI, ${primerNombre}!*\n\n` +
  `Confirmamos que *${data.business_name}* ya está en la lista del piloto para el *Mundial 2026* 🇨🇴⚽\n\n` +
  `Esto es lo que va a pasar:\n` +
  `✅ *48 horas antes* de cada partido de Colombia te enviamos aquí el contenido listo para publicar en Instagram\n` +
  `✅ Imagen + caption generados con IA, personalizados para tu negocio\n` +
  `✅ Solo debes copiar, pegar y publicar — sin complicaciones\n\n` +
  `📅 *Debut Colombia:* 17 de junio\n\n` +
  `Si tienes alguna pregunta, responde aquí mismo 👇\n\n` +
  `_— Equipo FanFest AI, Medellín 🟡🔵❤️_`;

return {
  json: {
    ...data,
    mensaje_bienvenida: mensaje
  }
};

// Verificar si el envío fue exitoso
const response = $input.first().json;
const businessData = $('Construir Mensaje de Bienvenida').first().json;

const exitoso = response.messages && response.messages[0]?.id;

return {
  json: {
    business_id: businessData.id,
    whatsapp_message_id: exitoso ? response.messages[0].id : null,
    whatsapp_enviado: exitoso ? true : false,
    whatsapp_error: exitoso ? null : JSON.stringify(response),
    nuevo_status: 'contacted'
  }
};
